import{state}from '../../state.js';import{fetchJson,spawnSession,sendSessionMessage}from '../../api.js';import{escapeHtml,formatDate,show,hide}from '../../utils/dom.js';export function getSessionElements(){return{showSpawnFormBtn:document.getElementById('showSpawnFormBtn'),spawnForm:document.getElementById('spawnForm'),spawnAgentSelect:document.getElementById('spawnAgentSelect'),spawnTaskInput:document.getElementById('spawnTaskInput'),confirmSpawnBtn:document.getElementById('confirmSpawnBtn'),cancelSpawnBtn:document.getElementById('cancelSpawnBtn'),spawnMsg:document.getElementById('spawnMsg'),sessionListEl:document.getElementById('sessionList'),sessionMessagesModal:document.getElementById('sessionMessagesModal'),closeSessionMessagesModal:document.getElementById('closeSessionMessagesModal'),sessionMessagesInfo:document.getElementById('sessionMessagesInfo'),sessionMessagesList:document.getElementById('sessionMessagesList'),sessionMessageInput:document.getElementById('sessionMessageInput'),sendSessionMessageBtn:document.getElementById('sendSessionMessageBtn'),sessionMessageMsg:document.getElementById('sessionMessageMsg')}}export function showSpawnForm(){const{spawnForm,spawnAgentSelect,spawnTaskInput}=getSessionElements();if (!spawnForm) return;show(spawnForm);if (spawnAgentSelect){const agents=state.runtime?.agents||[];spawnAgentSelect.innerHTML='<option value="">选择 Agent</option>'+agents.map(a=>`<option value="${a.id}">${escapeHtml(a.id)}</option>`).join('')}if (spawnTaskInput) spawnTaskInput.value='';if (spawnAgentSelect) spawnAgentSelect.focus()}export function hideSpawnForm(){const{spawnForm,spawnMsg}=getSessionElements();if (spawnForm) hide(spawnForm);if (spawnMsg) spawnMsg.textContent=''}export async function handleSpawnSession(){const{spawnAgentSelect,spawnTaskInput,spawnMsg}=getSessionElements();const agentId=spawnAgentSelect?.value;const task=spawnTaskInput?.value.trim();if (!agentId){if (spawnMsg) spawnMsg.textContent='请选择 Agent';return}if (!task){if (spawnMsg) spawnMsg.textContent='请输入任务描述';return}if (spawnMsg) spawnMsg.textContent='正在启动...';try{const res=await spawnSession(agentId,task);if (spawnMsg) spawnMsg.textContent=`会话已启动:${res.sessionKey}`;setTimeout(()=>{hideSpawnForm();refreshSessions()},1000)}catch (err){if (spawnMsg) spawnMsg.textContent=err.message}}export function renderSessions(){const{sessionListEl}=getSessionElements();if (!sessionListEl) return;const sessions=state.sessions||[];if (sessions.length===0){sessionListEl.innerHTML='<div class="empty-state muted">暂无会话</div>';return}sessionListEl.innerHTML=sessions.map(session=>{const statusClass=session.status==='active'?'success':'muted';return `<div class="session-item" data-session-key="${session.sessionKey}"><div class="session-item-header"><span class="session-status-dot ${statusClass}"></span><span class="session-agent-name">${escapeHtml(session.agentId)}</span></div><div class="session-item-meta muted small"><span>${session.sessionKey}</span><span>创建:${formatDate(session.createdAt)}</span></div><div class="session-item-actions"><button class="ghost tiny view-session-btn" data-session-key="${session.sessionKey}">查看消息</button></div></div>`}).join('');sessionListEl.querySelectorAll('.view-session-btn').forEach(btn=>{btn.addEventListener('click',()=>{const sessionKey=btn.dataset.sessionKey;openSessionMessagesModal(sessionKey)})})}let currentSessionKey=null;async function openSessionMessagesModal(sessionKey){const els=getSessionElements();if (!els.sessionMessagesModal) return;currentSessionKey=sessionKey;show(els.sessionMessagesModal);const session=state.sessions.find(s=>s.sessionKey===sessionKey);if (els.sessionMessagesInfo&&session){els.sessionMessagesInfo.innerHTML=`<div class="session-info-row"><span>Agent:${escapeHtml(session.agentId)}</span><span>状态:${session.status}</span><span>创建时间:${formatDate(session.createdAt)}</span></div>`}loadSessionMessages(sessionKey)}function hideSessionMessagesModal(){const{sessionMessagesModal}=getSessionElements();if (sessionMessagesModal) hide(sessionMessagesModal);currentSessionKey=null}async function loadSessionMessages(sessionKey){const{sessionMessagesList,sessionMessageMsg}=getSessionElements();try{const res=await fetchJson(`/api/sessions/${sessionKey}/messages`);if (!sessionMessagesList) return;if (!res.messages||res.messages.length===0){sessionMessagesList.innerHTML='<div class="muted small">暂无消息</div>';return}sessionMessagesList.innerHTML=res.messages.map(msg=>`<div class="session-message-item"><div class="session-message-role ${msg.role}">${msg.role==='user'?'用户':'Agent'}</div><div class="session-message-content">${escapeHtml(msg.message)}</div><div class="session-message-time muted small">${formatDate(msg.timestamp)}</div></div>`).join('')}catch (err){if (sessionMessageMsg) sessionMessageMsg.textContent=err.message}}async function handleSendSessionMessage(){const{sessionMessageInput,sessionMessageMsg}=getSessionElements();const message=sessionMessageInput?.value.trim();if (!message||!currentSessionKey) return;if (sessionMessageMsg) sessionMessageMsg.textContent='发送中...';try{await sendSessionMessage(currentSessionKey,message);if (sessionMessageInput) sessionMessageInput.value='';if (sessionMessageMsg) sessionMessageMsg.textContent='发送成功';loadSessionMessages(currentSessionKey)}catch (err){if (sessionMessageMsg) sessionMessageMsg.textContent=err.message}}async function refreshSessions(){const res=await fetchJson('/api/sessions');state.sessions=res.sessions||[];renderSessions()}export function initSessionComponent(){const els=getSessionElements();if (els.showSpawnFormBtn){els.showSpawnFormBtn.addEventListener('click',()=>showSpawnForm())}if (els.cancelSpawnBtn){els.cancelSpawnBtn.addEventListener('click',()=>hideSpawnForm())}if (els.confirmSpawnBtn){els.confirmSpawnBtn.addEventListener('click',()=>handleSpawnSession())}if (els.closeSessionMessagesModal){els.closeSessionMessagesModal.addEventListener('click',()=>hideSessionMessagesModal())}if (els.sendSessionMessageBtn){els.sendSessionMessageBtn.addEventListener('click',()=>handleSendSessionMessage())}const modalBackdrop=els.sessionMessagesModal?.querySelector('.modal-backdrop');if (modalBackdrop){modalBackdrop.addEventListener('click',()=>hideSessionMessagesModal())}return{showSpawnForm,hideSpawnForm,renderSessions,refreshSessions}}